1	// ABOUTME: Dashboard client — fetches session data, renders UI, handles interactions.
2	// ABOUTME: Vanilla JS with no build step; polls /api/sessions for updates.
3	
4	(function () {
5	  "use strict";
6	
7	  // --- State ---
8	  let dashboardData = null;
9	  let lastScannedTime = null;
10	  let expandedRepos = new Set(); // repo_root values that are expanded
11	  var timeFilterDays = Infinity; // max days back to show (Infinity = all)
12	
13	  // --- DOM refs ---
14	  const $loading = document.getElementById("loading");
15	  const $repoGroups = document.getElementById("repo-groups");
16	  const $nonRepoGroups = document.getElementById("non-repo-groups");
17	  const $chronoView = document.getElementById("chrono-view");
18	  const $emptyState = document.getElementById("empty-state");
19	  const $lastScan = document.getElementById("last-scan");
20	  const $btnRefresh = document.getElementById("btn-refresh");
21	  const $scanDays = document.getElementById("scan-days");
22	  const $timeSegments = document.getElementById("time-segments");
23	  const $searchOverlay = document.getElementById("search-overlay");
24	  const $searchInput = document.getElementById("search-input");
25	  const $searchResults = document.getElementById("search-results");
26	
27	  // --- Helpers ---
28	
29	  function timeAgo(isoString) {
30	    if (!isoString) return "--";
31	    const diff = Date.now() - new Date(isoString).getTime();
32	    const seconds = Math.floor(diff / 1000);
33	    if (seconds < 60) return seconds + "s ago";
34	    const minutes = Math.floor(seconds / 60);
35	    if (minutes < 60) return minutes + "m ago";
36	    const hours = Math.floor(minutes / 60);
37	    if (hours < 24) return hours + "h ago";
38	    const days = Math.floor(hours / 24);
39	    return days + "d ago";
40	  }
41	
42	  function statusCssClass(status) {
43	    return (status || "").replace(/\s+/g, "-");
44	  }
45	
46	  function isActiveDot(status) {
47	    return ["in progress", "likely in progress", "waiting for input"].includes(status);
48	  }
49	
50	  var INITIAL_VISIBLE = 10;
51	
52	  function escapeHtml(str) {
53	    const div = document.createElement("div");
54	    div.textContent = str || "";
55	    return div.innerHTML;
56	  }
57	
58	  function sessionLabel(session) {
59	    if (session.summary) return session.summary;
60	    if (session.slug) return session.slug;
61	    return session.id.substring(0, 8) + "\u2026";
62	  }
63	
64	  function allSessions() {
65	    if (!dashboardData) return [];
66	    var sessions = [];
67	    (dashboardData.repo_groups || []).forEach(function (g) {
68	      g.sessions.forEach(function (s) {
69	        sessions.push({ session: s, repoName: g.repo_name || "" });
70	      });
71	    });
72	    (dashboardData.non_repo_groups || []).forEach(function (g) {
73	      var name = g.cwd.split("/").filter(Boolean).pop() || g.cwd;
74	      g.sessions.forEach(function (s) {
75	        sessions.push({ session: s, repoName: name });
76	      });
77	    });
78	    return sessions;
79	  }
80	
81	  function fuzzyMatch(text, query) {
82	    var tLower = text.toLowerCase();
83	    var qLower = query.toLowerCase();
84	    var qi = 0;
85	    var indices = [];
86	    for (var ti = 0; ti < tLower.length && qi < qLower.length; ti++) {
87	      if (tLower[ti] === qLower[qi]) {
88	        indices.push(ti);
89	        qi++;
90	      }
91	    }
92	    if (qi < qLower.length) return null;
93	    // Score: prefer consecutive matches and matches at word boundaries
94	    var score = 0;
95	    for (var i = 0; i < indices.length; i++) {
96	      if (i > 0 && indices[i] === indices[i - 1] + 1) score += 10;
97	      if (indices[i] === 0 || text[indices[i] - 1] === " ") score += 5;
98	    }
99	    return { indices: indices, score: score };
100	  }
101	
102	  function highlightMatches(text, indices) {
103	    if (!indices || indices.length === 0) return escapeHtml(text);
104	    var result = "";
105	    var idxSet = new Set(indices);
106	    var inMark = false;
107	    for (var i = 0; i < text.length; i++) {
108	      if (idxSet.has(i) && !inMark) {
109	        result += "<mark>";
110	        inMark = true;
111	      } else if (!idxSet.has(i) && inMark) {
112	        result += "</mark>";
113	        inMark = false;
114	      }
115	      result += escapeHtml(text[i]);
116	    }
117	    if (inMark) result += "</mark>";
118	    return result;
119	  }
120	
121	  function parsePhaseDate(phase) {
122	    // Use start_date (ISO) if available, otherwise parse the period string
123	    if (phase.start_date) {
124	      return new Date(phase.start_date + "T00:00:00").getTime();
125	    }
126	    var period = phase.period || "";
127	    var now = new Date();
128	    if (period === "Today") return new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
129	    if (period === "Yesterday") return new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1).getTime();
130	    // Parse "Mar 17" or "Mar 10-12" (use first date in range)
131	    var months = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
132	    var m = period.match(/^([A-Z][a-z]{2})\s+(\d+)/);
133	    if (m && months[m[1]] !== undefined) {
134	      var year = now.getFullYear();
135	      var d = new Date(year, months[m[1]], parseInt(m[2], 10));
136	      // If the parsed date is in the future, it's from last year
137	      if (d.getTime() > now.getTime() + 86400000) d.setFullYear(year - 1);
138	      return d.getTime();
139	    }
140	    return 0; // can't parse — don't filter
141	  }
142	
143	  function filterSessionByTime(session) {
144	    if (timeFilterDays === Infinity) return true;
145	    if (!session.last_active) return false;
146	    var cutoff = Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
147	    return new Date(session.last_active).getTime() >= cutoff;
148	  }
149	
150	  function filterGroupSessions(group) {
151	    return group.sessions.filter(filterSessionByTime);
152	  }
153	
154	  // --- Rendering ---
155	
156	  function isSessionFresh(session) {
157	    if (!session.last_active) return false;
158	    var hourAgo = Date.now() - 60 * 60 * 1000;
159	    return new Date(session.last_active).getTime() >= hourAgo;
160	  }
161	
162	  function renderSessionRow(session) {
163	    const cssCls = statusCssClass(session.status);
164	    const row = document.createElement("div");
165	    row.className = "session-row" + (isSessionFresh(session) ? " session-fresh" : "");
166	    row.innerHTML =
167	      '<div class="status-dot ' + cssCls + '"></div>' +
168	      '<div class="session-summary">' + escapeHtml(sessionLabel(session)) + "</div>" +
169	      '<span class="status-label ' + cssCls + '">' + escapeHtml(session.status) + "</span>" +
170	      '<span class="time-ago">' + timeAgo(session.last_active) + "</span>" +
171	      '<span class="source-badge ' + session.source + '">' + session.source + "</span>";
172	
173	    row.addEventListener("click", function () {
174	      launchSession(session, row);
175	    });
176	
177	    return row;
178	  }
179	
180	  // Octocat SVG icon for git repo groups
181	  var OCTOCAT_SVG = '<svg class="octocat-icon" viewBox="0 0 16 16" width="14" height="14" fill="currentColor">' +
182	    '<path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49' +
183	    '-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82' +
184	    '.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15' +
185	    '-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27.68 0 1.36.09 2 .27 1.53-1.04 2.2-.82' +
186	    ' 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48' +
187	    ' 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.013 8.013 0 0016 8c0-4.42-3.58-8-8-8z"/></svg>';
188	
189	  function buildGroupHeaderHtml(opts, isExpanded, sessionCount) {
190	    var chevron = '<span class="repo-chevron ' + (isExpanded ? "expanded" : "") + '" aria-hidden="true">\u25B6</span>';
191	    var icon = opts.icon || "";
192	    var name = '<span class="repo-name-display">' + escapeHtml(opts.displayName) + "</span>";
193	    var meta = '<span class="repo-meta-line">' + opts.metaText + "</span>";
194	    var btn = '<button class="btn-new-session" title="New Claude session in ' + escapeHtml(opts.cwd) + '" aria-label="New session in ' + escapeHtml(opts.displayName) + '">+</button>';
195	
196	    return (
197	      '<div class="repo-header-left">' + chevron + icon +
198	        '<div class="repo-header-info">' + name + meta + '</div>' +
199	      "</div>" +
200	      '<div class="repo-header-right">' + btn + timeAgo(opts.lastActive) + "</div>"
201	    );
202	  }
203	
204	  function renderGroup(opts, filteredSessions) {
205	    if (filteredSessions.length === 0) return null;
206	
207	    var groupKey = opts.groupKey;
208	    var isExpanded = expandedRepos.has(groupKey);
209	    var container = document.createElement("div");
210	    container.className = "repo-group";
211	
212	    var header = document.createElement("div");
213	    header.className = "repo-header";
214	    header.setAttribute("role", "button");
215	    header.setAttribute("aria-expanded", isExpanded ? "true" : "false");
216	    header.setAttribute("tabindex", "0");
217	    header.innerHTML = buildGroupHeaderHtml(opts, isExpanded, filteredSessions.length);
218	
219	    var sessionList = document.createElement("div");
220	    sessionList.className = "session-list" + (isExpanded ? "" : " collapsed");
221	
222	    // Render timeline if present, filtered by time slider
223	    if (opts.timeline && opts.timeline.length > 0) {
224	      var timelineEl = document.createElement("div");
225	      timelineEl.className = "repo-timeline";
226	      var cutoff = timeFilterDays === Infinity ? 0 : Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
227	      opts.timeline.forEach(function (phase) {
228	        if (cutoff > 0) {
229	          var phaseTime = parsePhaseDate(phase);
230	          if (phaseTime > 0 && phaseTime < cutoff) return;
231	        }
232	        var phaseEl = document.createElement("div");
233	        phaseEl.className = "timeline-phase";
234	        phaseEl.innerHTML =
235	          '<span class="timeline-period">' + escapeHtml(phase.period) + '</span>' +
236	          '<span class="timeline-desc">' + escapeHtml(phase.description) + '</span>';
237	        timelineEl.appendChild(phaseEl);
238	      });
239	      if (timelineEl.children.length > 0) {
240	        sessionList.appendChild(timelineEl);
241	      }
242	    }
243	
244	    var showingAll = filteredSessions.length <= INITIAL_VISIBLE;
245	
246	    function renderVisibleSessions() {
247	      var timeline = sessionList.querySelector(".repo-timeline");
248	      sessionList.innerHTML = "";
249	      if (timeline) sessionList.appendChild(timeline);
250	
251	      var toShow = showingAll ? filteredSessions : filteredSessions.slice(0, INITIAL_VISIBLE);
252	      toShow.forEach(function (session) {
253	        sessionList.appendChild(renderSessionRow(session));
254	      });
255	      if (!showingAll) {
256	        var moreBtn = document.createElement("div");
257	        moreBtn.className = "show-more-btn";
258	        moreBtn.textContent = "Show all " + filteredSessions.length + " sessions";
259	        moreBtn.addEventListener("click", function (e) {
260	          e.stopPropagation();
261	          showingAll = true;
262	          renderVisibleSessions();
263	          sessionList.style.maxHeight = sessionList.scrollHeight + "px";
264	        });
265	        sessionList.appendChild(moreBtn);
266	      }
267	    }
268	    renderVisibleSessions();
269	
270	    header.querySelector(".btn-new-session").addEventListener("click", function (e) {
271	      e.stopPropagation();
272	      openNewSession(opts.cwd);
273	    });
274	
275	    header.addEventListener("click", function () {
276	      if (expandedRepos.has(groupKey)) {
277	        expandedRepos.delete(groupKey);
278	        sessionList.classList.add("collapsed");
279	        header.querySelector(".repo-chevron").classList.remove("expanded");
280	        header.setAttribute("aria-expanded", "false");
281	      } else {
282	        expandedRepos.add(groupKey);
283	        sessionList.classList.remove("collapsed");
284	        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
285	        header.querySelector(".repo-chevron").classList.add("expanded");
286	        header.setAttribute("aria-expanded", "true");
287	      }
288	    });
289	
290	    if (isExpanded) {
291	      requestAnimationFrame(function () {
292	        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
293	      });
294	    }
295	
296	    container.appendChild(header);
297	    container.appendChild(sessionList);
298	    return container;
299	  }
300	
301	  function renderRepoGroup(group, filteredSessions) {
302	    var metaParts = [];
303	    if (group.git_branch) metaParts.push(group.git_branch);
304	    if (group.git_dirty) metaParts.push('<span class="dirty">dirty</span>');
305	    if (group.unpushed_commits > 0) metaParts.push('<span class="unpushed">' + group.unpushed_commits + " unpushed</span>");
306	    if (!group.git_dirty && group.unpushed_commits === 0) metaParts.push("clean");
307	    metaParts.push(filteredSessions.length + " sessions");
308	
309	    return renderGroup({
310	      groupKey: group.repo_root,
311	      displayName: group.repo_name,
312	      icon: OCTOCAT_SVG,
313	      metaText: metaParts.join(", "),
314	      cwd: group.repo_root,
315	      lastActive: group.last_active,
316	      timeline: group.timeline,
317	    }, filteredSessions);
318	  }
319	
320	  function renderNonRepoGroup(group, filteredSessions) {
321	    var displayName = group.cwd.split("/").filter(Boolean).pop() || group.cwd;
322	
323	    return renderGroup({
324	      groupKey: group.cwd,
325	      displayName: displayName,
326	      icon: "",
327	      metaText: filteredSessions.length + " sessions",
328	      cwd: group.cwd,
329	      lastActive: group.last_active,
330	      timeline: group.timeline,
331	    }, filteredSessions);
332	  }
333	
334	  function render() {
335	    if (!dashboardData) return;
336	
337	    $loading.classList.add("hidden");
338	
339	    var hasRepos = (dashboardData.repo_groups || []).length > 0;
340	    var hasNonRepos = (dashboardData.non_repo_groups || []).length > 0;
341	
342	    if (!hasRepos && !hasNonRepos) {
343	      $emptyState.classList.remove("hidden");
344	      $repoGroups.classList.add("hidden");
345	      $nonRepoGroups.classList.add("hidden");
346	      $chronoView.classList.add("hidden");
347	      return;
348	    }
349	
350	    $emptyState.classList.add("hidden");
351	    $chronoView.classList.add("hidden");
352	    $repoGroups.classList.remove("hidden");
353	    $nonRepoGroups.classList.add("hidden");
354	
355	    // Combine repo and non-repo groups into one list sorted by last_active
356	    var allGroups = [];
357	    (dashboardData.repo_groups || []).forEach(function (g) {
358	      allGroups.push({ type: "repo", group: g, last_active: g.last_active });
359	    });
360	    (dashboardData.non_repo_groups || []).forEach(function (g) {
361	      allGroups.push({ type: "non-repo", group: g, last_active: g.last_active });
362	    });
363	    allGroups.sort(function (a, b) {
364	      return new Date(b.last_active) - new Date(a.last_active);
365	    });
366	
367	    // Auto-expand the first group on initial render
368	    if (expandedRepos.size === 0 && allGroups.length > 0) {
369	      var firstGroup = allGroups[0];
370	      var expandKey = firstGroup.type === "repo" ? firstGroup.group.repo_root : firstGroup.group.cwd;
371	      expandedRepos.add(expandKey);
372	    }
373	
374	    $repoGroups.innerHTML = "";
375	    allGroups.forEach(function (entry) {
376	      var filtered = filterGroupSessions(entry.group);
377	      var el = entry.type === "repo"
378	        ? renderRepoGroup(entry.group, filtered)
379	        : renderNonRepoGroup(entry.group, filtered);
380	      if (el) $repoGroups.appendChild(el);
381	    });
382	  }
383	
384	  // --- API ---
385	
386	  function fetchSessions() {
387	    return fetch("/api/sessions")
388	      .then(function (res) { return res.json(); })
389	      .then(function (data) {
390	        dashboardData = data;
391	        lastScannedTime = data.last_scanned;
392	        render();
393	        updateLastScan();
394	      })
395	      .catch(function (err) {
396	        console.error("Failed to fetch sessions:", err);
397	      });
398	  }
399	
400	  function refreshSessions() {
401	    var days = parseInt($scanDays.value, 10) || 7;
402	    $btnRefresh.classList.add("spinning");
403	    $btnRefresh.textContent = "Refreshing...";
404	    return fetch("/api/refresh?scan_days=" + days)
405	      .then(function (res) { return res.json(); })
406	      .then(function (data) {
407	        dashboardData = data;
408	        lastScannedTime = data.last_scanned;
409	        render();
410	        updateLastScan();
411	      })
412	      .catch(function (err) {
413	        console.error("Failed to refresh:", err);
414	      })
415	      .finally(function () {
416	        $btnRefresh.classList.remove("spinning");
417	        $btnRefresh.textContent = "Refresh";
418	      });
419	  }
420	
421	  function launchSession(session, rowEl) {
422	    rowEl.classList.add("launched");
423	    setTimeout(function () { rowEl.classList.remove("launched"); }, 500);
424	    var mode = localStorage.getItem("ak-view-mode") || "chat";
425	    if (mode === "chat" && window.AgentChat) {
426	      window.AgentChat.openChat(session);
427	    } else {
428	      openTerminal(session);
429	    }
430	  }
431	
432	  // --- Terminal Tabs ---
433	
434	  var terminals = {};       // tabId → tabData
435	  var activeTabId = null;
436	  var tabIdCounter = 0;
437	  var resizeListenerAttached = false;
438	
439	  var $terminalPanel = document.getElementById("terminal-panel");
440	  var $terminalContainer = document.getElementById("terminal-container");
441	  var $terminalTabs = document.getElementById("terminal-tabs");
442	  var $terminalClose = document.getElementById("terminal-close");
443	
444	  // Re-fit active terminal on any container size change (panel open/close,
445	  // tab switch, browser resize, etc.)
446	  var terminalResizeObserver = new ResizeObserver(function () {
447	    if (activeTabId && terminals[activeTabId]) {
448	      terminals[activeTabId].fitAddon.fit();
449	    }
450	  });
451	  terminalResizeObserver.observe($terminalContainer);
452	
453	  function generateTabId() {
454	    return "tab-" + (tabIdCounter++);
455	  }
456	
457	  function renderTabs() {
458	    $terminalTabs.innerHTML = "";
459	    var ids = Object.keys(terminals);
460	    ids.forEach(function (tabId) {
461	      var tab = terminals[tabId];
462	      var el = document.createElement("div");
463	      el.className = "terminal-tab" + (tabId === activeTabId ? " active" : "") + (tab.ended ? " ended" : "");
464	      el.innerHTML =
465	        '<span class="terminal-tab-title">' + escapeHtml(tab.title) + '</span>' +
466	        '<span class="terminal-tab-close">&times;</span>';
467	
468	      el.querySelector(".terminal-tab-title").addEventListener("click", function () {
469	        switchTab(tabId);
470	      });
471	      el.querySelector(".terminal-tab-close").addEventListener("click", function (e) {
472	        e.stopPropagation();
473	        closeTab(tabId);
474	      });
475	
476	      $terminalTabs.appendChild(el);
477	    });
478	  }
479	
480	  function switchTab(tabId) {
481	    if (!terminals[tabId]) return;
482	    if (activeTabId && terminals[activeTabId]) {
483	      terminals[activeTabId].container.classList.remove("active");
484	    }
485	    activeTabId = tabId;
486	    terminals[tabId].container.classList.add("active");
487	    terminals[tabId].fitAddon.fit();
488	    terminals[tabId].term.focus();
489	    renderTabs();
490	  }
491	
492	  function closeTab(tabId) {
493	    var tab = terminals[tabId];
494	    if (!tab) return;
495	    tab.ws.close();
496	    tab.term.dispose();
497	    tab.container.remove();
498	    delete terminals[tabId];
499	
500	    if (activeTabId === tabId) {
501	      var remaining = Object.keys(terminals);
502	      if (remaining.length > 0) {
503	        switchTab(remaining[remaining.length - 1]);
504	      } else {
505	        activeTabId = null;
506	        $terminalPanel.classList.add("hidden");
507	        document.body.classList.remove("terminal-open");
508	        window.removeEventListener("resize", handleTerminalResize);
509	        resizeListenerAttached = false;
510	      }
511	    }
512	    renderTabs();
513	  }
514	
515	  function createTerminalTab(title, wsParams, sessionId) {
516	    var tabId = generateTabId();
517	
518	    var container = document.createElement("div");
519	    container.className = "terminal-tab-container";
520	    $terminalContainer.appendChild(container);
521	
522	    var term = new Terminal({
523	      fontFamily: '"JetBrains Mono", "SF Mono", monospace',
524	      fontSize: 13,
525	      theme: {
526	        background: "#111111",
527	        foreground: "#FAFAFA",
528	        cursor: "#FF4D00",
529	      },
530	      cursorBlink: true,
531	    });
532	
533	    var fitAddon = new FitAddon.FitAddon();
534	    term.loadAddon(fitAddon);
535	    term.loadAddon(new WebLinksAddon.WebLinksAddon());
536	
537	    term.open(container);
538	
539	    var tabData = {
540	      id: tabId,
541	      term: term,
542	      ws: null,
543	      fitAddon: fitAddon,
544	      container: container,
545	      title: title,
546	      ended: false,
547	      sessionId: sessionId,
548	    };
549	    terminals[tabId] = tabData;
550	
551	    $terminalPanel.classList.remove("hidden");
552	    document.body.classList.add("terminal-open");
553	
554	    // Hide previous active tab, show this one
555	    if (activeTabId && terminals[activeTabId]) {
556	      terminals[activeTabId].container.classList.remove("active");
557	    }
558	    activeTabId = tabId;
559	    container.classList.add("active");
560	
561	    // Defer fit + WebSocket connection until container is fully laid out.
562	    // Double-rAF ensures the browser has completed layout after display change.
563	    requestAnimationFrame(function () {
564	      requestAnimationFrame(function () {
565	        fitAddon.fit();
566	
567	        // Pass terminal dimensions as query params so the PTY spawns at the
568	        // correct size from the start (avoids garbled initial render).
569	        var params = new URLSearchParams(wsParams);
570	        params.set("cols", term.cols);
571	        params.set("rows", term.rows);
572	        var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
573	        var wsUrl =
574	          wsProtocol + "//" + location.host + "/ws/terminal?" + params.toString();
575	        var ws = new WebSocket(wsUrl);
576	        tabData.ws = ws;
577	
578	        ws.onopen = function () {
579	          ws.send(
580	            JSON.stringify({ type: "resize", cols: term.cols, rows: term.rows })
581	          );
582	          term.focus();
583	        };
584	
585	        ws.onmessage = function (evt) {
586	          term.write(evt.data);
587	        };
588	
589	        ws.onclose = function () {
590	          term.write("\r\n\x1b[90m[session ended]\x1b[0m\r\n");
591	          tabData.ended = true;
592	          renderTabs();
593	        };
594	
595	        term.onData(function (data) {
596	          if (ws.readyState === WebSocket.OPEN) ws.send(data);
597	        });
598	
599	        term.onResize(function (size) {
600	          if (ws.readyState === WebSocket.OPEN) {
601	            ws.send(
602	              JSON.stringify({ type: "resize", cols: size.cols, rows: size.rows })
603	            );
604	          }
605	        });
606	      });
607	    });
608	
609	    if (!resizeListenerAttached) {
610	      window.addEventListener("resize", handleTerminalResize);
611	      resizeListenerAttached = true;
612	    }
613	
614	    renderTabs();
615	    return tabId;
616	  }
617	
618	  function openTerminal(session) {
619	    // If this session already has a tab, switch to it
620	    var ids = Object.keys(terminals);
621	    for (var i = 0; i < ids.length; i++) {
622	      if (terminals[ids[i]].sessionId === session.id) {
623	        switchTab(ids[i]);
624	        return;
625	      }
626	    }
627	    createTerminalTab(sessionLabel(session), {
628	      source: session.source,
629	      session_id: session.id,
630	      cwd: session.cwd,
631	    }, session.id);
632	  }
633	
634	  function openNewSession(cwd) {
635	    var mode = localStorage.getItem("ak-view-mode") || "chat";
636	    if (mode === "chat" && window.AgentChat) {
637	      window.AgentChat.openNewChat(cwd);
638	    } else {
639	      var displayName = cwd.split("/").filter(Boolean).pop() || cwd;
640	      createTerminalTab("New: " + displayName, { mode: "new", cwd: cwd }, null);
641	    }
642	  }
643	
644	  function handleTerminalResize() {
