676	
677	  // --- Search Overlay ---
678	
679	  var searchSelectedIdx = 0;
680	  var searchMatches = [];
681	  var previouslyFocusedElement = null;
682	
683	  function openSearch() {
684	    previouslyFocusedElement = document.activeElement;
685	    $searchOverlay.classList.remove("hidden");
686	    $searchInput.value = "";
687	    $searchResults.innerHTML = "";
688	    searchSelectedIdx = 0;
689	    searchMatches = [];
690	    $searchInput.focus();
691	  }
692	
693	  function closeSearch() {
694	    $searchOverlay.classList.add("hidden");
695	    $searchInput.value = "";
696	    $searchResults.innerHTML = "";
697	    if (previouslyFocusedElement && previouslyFocusedElement.focus) {
698	      previouslyFocusedElement.focus();
699	    }
700	    previouslyFocusedElement = null;
701	  }
702	
703	  function performSearch(query) {
704	    $searchResults.innerHTML = "";
705	    searchSelectedIdx = 0;
706	
707	    if (!query.trim()) {
708	      searchMatches = [];
709	      return;
710	    }
711	
712	    var all = allSessions();
713	    var scored = [];
714	    all.forEach(function (entry) {
715	      var label = sessionLabel(entry.session);
716	      var searchText = label + " " + entry.repoName + " " + (entry.session.status || "");
717	      var m = fuzzyMatch(searchText, query);
718	      if (m) {
719	        // Re-match just the label for highlighting
720	        var labelMatch = fuzzyMatch(label, query);
721	        scored.push({
722	          session: entry.session,
723	          repoName: entry.repoName,
724	          score: m.score,
725	          labelIndices: labelMatch ? labelMatch.indices : [],
726	        });
727	      }
728	    });
729	
730	    scored.sort(function (a, b) { return b.score - a.score; });
731	    searchMatches = scored.slice(0, 50);
732	
733	    if (searchMatches.length === 0) {
734	      $searchResults.innerHTML = '<div class="search-no-results">No matches</div>';
735	      return;
736	    }
737	
738	    searchMatches.forEach(function (match, idx) {
739	      var row = document.createElement("div");
740	      row.className = "search-result-row" + (idx === 0 ? " selected" : "");
741	      var cssCls = statusCssClass(match.session.status);
742	      row.innerHTML =
743	        '<div class="status-dot ' + cssCls + '"></div>' +
744	        '<div>' +
745	          '<div class="search-result-summary">' +
746	            highlightMatches(sessionLabel(match.session), match.labelIndices) +
747	          '</div>' +
748	          '<span class="search-result-repo">' + escapeHtml(match.repoName) + '</span>' +
749	        '</div>' +
750	        '<span class="status-label ' + cssCls + '">' +
751	          escapeHtml(match.session.status) + '</span>' +
752	        '<span class="time-ago">' + timeAgo(match.session.last_active) + '</span>';
753	
754	      row.addEventListener("click", function () {
755	        closeSearch();
756	        launchFromSearch(match.session);
757	      });
758	      $searchResults.appendChild(row);
759	    });
760	  }
761	
762	  function launchFromSearch(session) {
763	    openTerminal(session);
764	  }
765	
766	  function updateSearchSelection() {
767	    var rows = $searchResults.querySelectorAll(".search-result-row");
768	    rows.forEach(function (r, i) {
769	      r.classList.toggle("selected", i === searchSelectedIdx);
770	    });
771	    if (rows[searchSelectedIdx]) {
772	      rows[searchSelectedIdx].scrollIntoView({ block: "nearest" });
773	    }
774	  }
775	
776	  $searchInput.addEventListener("input", function () {
777	    performSearch($searchInput.value);
778	  });
779	
780	  $searchInput.addEventListener("keydown", function (e) {
781	    if (e.key === "Escape") {
782	      e.preventDefault();
783	      closeSearch();
784	    } else if (e.key === "ArrowDown") {
785	      e.preventDefault();
786	      if (searchMatches.length > 0) {
787	        searchSelectedIdx = Math.min(searchSelectedIdx + 1, searchMatches.length - 1);
788	        updateSearchSelection();
789	      }
790	    } else if (e.key === "ArrowUp") {
791	      e.preventDefault();
792	      if (searchMatches.length > 0) {
793	        searchSelectedIdx = Math.max(searchSelectedIdx - 1, 0);
794	        updateSearchSelection();
795	      }
796	    } else if (e.key === "Enter") {
797	      e.preventDefault();
798	      if (searchMatches.length > 0 && searchMatches[searchSelectedIdx]) {
799	        closeSearch();
800	        launchFromSearch(searchMatches[searchSelectedIdx].session);
801	      }
802	    }
803	  });
804	
805	  $searchOverlay.addEventListener("click", function (e) {
806	    if (e.target === $searchOverlay) closeSearch();
807	  });
808	
809	  // --- Keyboard Help Overlay ---
810	
811	  var $helpOverlay = document.getElementById("help-overlay");
812	
813	  function openHelp() {
814	    $helpOverlay.classList.remove("hidden");
815	  }
816	
817	  function closeHelp() {
818	    $helpOverlay.classList.add("hidden");
819	  }
820	
821	  $helpOverlay.addEventListener("click", function (e) {
822	    if (e.target === $helpOverlay) closeHelp();
823	  });
824	
825	  // --- Group Navigation (j/k) ---
826	
827	  var focusedGroupIdx = -1;
828	
829	  function getAllGroupElements() {
830	    return Array.from($repoGroups.querySelectorAll(".repo-group"));
831	  }
832	
833	  function setGroupFocus(idx) {
834	    var groups = getAllGroupElements();
835	    // Clear previous focus
836	    groups.forEach(function (el) {
837	      el.classList.remove("group-focused");
838	    });
839	    if (idx < 0 || idx >= groups.length) {
840	      focusedGroupIdx = -1;
841	      return;
842	    }
843	    focusedGroupIdx = idx;
844	    groups[idx].classList.add("group-focused");
845	    groups[idx].scrollIntoView({ block: "nearest", behavior: "smooth" });
846	  }
847	
848	  function toggleFocusedGroup() {
849	    var groups = getAllGroupElements();
850	    if (focusedGroupIdx < 0 || focusedGroupIdx >= groups.length) return;
851	    var header = groups[focusedGroupIdx].querySelector(".repo-header");
852	    if (header) header.click();
853	  }
854	
855	  // --- Global Keyboard Handler ---
856	
857	  document.addEventListener("keydown", function (e) {
858	    // Don't trigger if typing in an input or textarea
859	    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
860	
861	    // Help overlay takes priority for close
862	    if (!$helpOverlay.classList.contains("hidden")) {
863	      if (e.key === "Escape" || e.key === "?") {
864	        e.preventDefault();
865	        closeHelp();
866	      }
867	      return;
868	    }
869	
870	    // Escape closes active terminal tab (returns focus to dashboard)
871	    if (e.key === "Escape" && activeTabId) {
872	      e.preventDefault();
873	      closeTab(activeTabId);
874	      return;
875	    }
876	
877	    // When terminal is focused, only Escape works (handled above)
878	    if (activeTabId) return;
879	
880	    if (e.key === "/") {
881	      e.preventDefault();
882	      openSearch();
883	    } else if (e.key === "?") {
884	      e.preventDefault();
885	      openHelp();
886	    } else if (e.key === "r") {
887	      e.preventDefault();
888	      refreshSessions();
889	    } else if (e.key === "j") {
890	      e.preventDefault();
891	      var groups = getAllGroupElements();
892	      if (groups.length > 0) {
893	        setGroupFocus(Math.min(focusedGroupIdx + 1, groups.length - 1));
894	      }
895	    } else if (e.key === "k") {
896	      e.preventDefault();
897	      if (focusedGroupIdx > 0) {
898	        setGroupFocus(focusedGroupIdx - 1);
899	      }
900	    } else if (e.key === "Enter" && focusedGroupIdx >= 0) {
901	      e.preventDefault();
902	      toggleFocusedGroup();
903	    }
904	  });
