  font-family: var(--font-display);
  font-size: 20px;
  color: var(--text-primary);
  margin-bottom: 16px;
}

.empty-state-body {
  max-width: 480px;
  margin: 0 auto;
  line-height: 1.7;
}

.empty-state-body p {
  margin-bottom: 8px;
}

.empty-state code {
  font-family: var(--font-mono);
