/* ===== Dark Mode (shared rules for both auto and manual) ===== */

/* Dark mode variables — applied by media query (auto) or data-theme attribute (manual) */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]) {
    --bg-primary: #0e0e0e;
    --bg-secondary: #181818;
    --bg-hover: #222222;
    --bg-surface: #1e1e1e;
    --text-primary: #EEEEEE;
    --text-secondary: #BBBBBB;
    --text-muted: #777777;
    --border: #2e2e2e;
    --border-light: #252525;
    --accent-dim: rgba(255, 77, 0, 0.15);
    --bg-code: #0a0a0a;
    --border-code: #2e2e2e;
    --bg-code-inline: rgba(255, 255, 255, 0.08);
    --bg-table-header: rgba(255, 255, 255, 0.05);
    --border-table: #444444;
    --status-done: #888888;
    --status-likely-done: #666666;
    --badge-claude: #DDDDDD;
    --badge-codex: #AAAAAA;
  }
}

[data-theme="dark"] {
  --bg-primary: #0e0e0e;
  --bg-secondary: #181818;
  --bg-hover: #222222;
  --bg-surface: #1e1e1e;
  --text-primary: #EEEEEE;
  --text-secondary: #BBBBBB;
  --text-muted: #777777;
  --border: #2e2e2e;
  --border-light: #252525;
  --accent-dim: rgba(255, 77, 0, 0.15);
  --bg-code: #0a0a0a;
  --border-code: #2e2e2e;
  --bg-code-inline: rgba(255, 255, 255, 0.08);
  --bg-table-header: rgba(255, 255, 255, 0.05);
  --border-table: #444444;
  --status-done: #888888;
  --status-likely-done: #666666;
  --badge-claude: #DDDDDD;
  --badge-codex: #AAAAAA;
}

/* Dark mode component overrides — scoped to both auto and manual triggers */
@media (prefers-color-scheme: dark) { :root:not([data-theme="light"]) ~ body .header,
  :root:not([data-theme="light"]) .header { box-shadow: 0 1px 6px rgba(0, 0, 0, 0.3); border-bottom-color: #222; }
}

/* Shared dark overrides for manual and auto dark mode */
:is([data-theme="dark"], .dark-active) .header { box-shadow: 0 1px 6px rgba(0, 0, 0, 0.3); border-bottom-color: #222; }
:is([data-theme="dark"], .dark-active) .repo-group { box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2); }
:is([data-theme="dark"], .dark-active) .repo-group:hover { box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3); }
:is([data-theme="dark"], .dark-active) .status-label.done { background: rgba(255, 255, 255, 0.06); border-color: rgba(255, 255, 255, 0.08); }
:is([data-theme="dark"], .dark-active) .status-label.likely-done { background: rgba(255, 255, 255, 0.04); border-color: rgba(255, 255, 255, 0.06); }
:is([data-theme="dark"], .dark-active) .status-label.waiting-for-input { color: #ffd700; background: rgba(255, 215, 0, 0.15); }
:is([data-theme="dark"], .dark-active) .search-overlay { background: rgba(0, 0, 0, 0.6); }
:is([data-theme="dark"], .dark-active) .search-box { box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5), 0 0 0 1px rgba(255, 255, 255, 0.05); }
:is([data-theme="dark"], .dark-active) .source-badge { border-color: var(--border); }
:is([data-theme="dark"], .dark-active) .time-seg.active { background: var(--text-primary); color: var(--bg-secondary); }
:is([data-theme="dark"], .dark-active) .search-hint-bar { background: var(--bg-surface); border-color: var(--border); }
:is([data-theme="dark"], .dark-active) .search-hint-bar kbd { background: var(--bg-primary); border-color: var(--border); }
:is([data-theme="dark"], .dark-active) .chat-bubble.user { box-shadow: 0 1px 4px rgba(255, 77, 0, 0.15); }
:is([data-theme="dark"], .dark-active) .chat-bubble.assistant { border-color: var(--border); }
:is([data-theme="dark"], .dark-active) .meta-sep { color: #444; }
:is([data-theme="dark"], .dark-active) .repo-meta-line .dirty { color: #fc8181; }
:is([data-theme="dark"], .dark-active) .repo-meta-line .clean { color: #68d391; }

/* Auto dark mode component overrides (only when not manually set to light) */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]) .header { box-shadow: 0 1px 6px rgba(0, 0, 0, 0.3); border-bottom-color: #222; }
  :root:not([data-theme="light"]) .repo-group { box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2); }
  :root:not([data-theme="light"]) .repo-group:hover { box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3); }
  :root:not([data-theme="light"]) .status-label.done { background: rgba(255, 255, 255, 0.06); border-color: rgba(255, 255, 255, 0.08); }
  :root:not([data-theme="light"]) .status-label.likely-done { background: rgba(255, 255, 255, 0.04); border-color: rgba(255, 255, 255, 0.06); }
  :root:not([data-theme="light"]) .status-label.waiting-for-input { color: #ffd700; background: rgba(255, 215, 0, 0.15); }
  :root:not([data-theme="light"]) .search-overlay { background: rgba(0, 0, 0, 0.6); }
  :root:not([data-theme="light"]) .search-box { box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5), 0 0 0 1px rgba(255, 255, 255, 0.05); }
  :root:not([data-theme="light"]) .source-badge { border-color: var(--border); }
  :root:not([data-theme="light"]) .time-seg.active { background: var(--text-primary); color: var(--bg-secondary); }
  :root:not([data-theme="light"]) .search-hint-bar { background: var(--bg-surface); border-color: var(--border); }
  :root:not([data-theme="light"]) .search-hint-bar kbd { background: var(--bg-primary); border-color: var(--border); }
  :root:not([data-theme="light"]) .chat-bubble.user { box-shadow: 0 1px 4px rgba(255, 77, 0, 0.15); }
  :root:not([data-theme="light"]) .chat-bubble.assistant { border-color: var(--border); }
  :root:not([data-theme="light"]) .meta-sep { color: #444; }
  :root:not([data-theme="light"]) .repo-meta-line .dirty { color: #fc8181; }
  :root:not([data-theme="light"]) .repo-meta-line .clean { color: #68d391; }
}

